					'שָׁלוֹם, אֲנִי בֵּת!\n  \n  \n\nיָד, יָדַ֫יִם, שָׂפָה, שְׂפָתַ֫יִם אַף, פֶּה, כַּף, כַּפַּ֫יִם, עַ֫יִן עֵינַ֫יִם, עַיִן, בֶּ֫טֶן, רֺאשׁ בֶּטֶן, יָדַיִם, רֶ֫גֶל, רַגְלַ֫יִם כַּף־רֶ֫גֶל, יָדַיִם וְרַגְלַיִם פָּנִים, אֹ֫זֶן, עַיִן, אַף שְׂפָתַיִם, רַגְלַיִם, עַיִן עֵינַיִם, אָזְנַ֫יִם, פָּנִים, רַגְלַיִם         \n\n\nרַגְלַיִם בַּמִּדְבָּר, רַגְלַיִם בַּשָּׂדֶה רַגְלַיִם בַּבַּיִת, רַגְלַיִם בָּאֹהֶל רַגְלַיִם בַּדֶּרֶךְ   \nרֹאשׁ וְיָדַיִם, רֺאשׁ, עֵינַיִם, אַף, פֶּה, אָזְנַיִם\nיָד קְטַנָּה, יָדַיִם קְטַנּוֹת וְיָדַיִם גְּדֹלוֹת\nרֶגֶל קְטַנָּה, רַגְלַיִם קְטַנּוֹת\nאֹזֶן קְטַנָּה, אָזְנַיִם גְּדֹלוֹת  \nהַיָּדַיִם עַל־הָרֹאשׁ׃ הַיָּדַיִם אַחֲרֵי הָרֹאשׁ׃ הַיָּד עַל־הַפֶּה׃ הַיָּדַיִם עַל־הָאָזְנַיִם׃  \nהַיָּדַיִם עַל־הָעֵינַיִם׃ הַיָּדַיִם עַל־הַבֶּטֶן׃\nהַיָּד הַזֹּאת עַל־הָרֹאשׁ וְהַיָּד הַזֹּאת לִפְנֵי הָרֹאשׁ׃  \nבֶּטֶן גָּמָל, רֺאשׁ חֲמוֹר  \nבֶּטֶן אִשָּׁה, אַף גָּמָל, רֶגֶל עֵז\nאֹזֶן עֵז, בֶּטֶן חֲמוֹר, אֹזֶן חֲמוֹר  \nרֹאשׁ אִשָּׁה, אַף אִשָּׁה  \nאֹזֶן פָּרָה, אֹזֶן אִשָּׁה, יַד אִשָּׁה\nבֶּטֶן אִשָּׁה, יַד אִישׁ, בֶּטֶן אִישׁ\nיַד אִשָּׁה וְיַד אִישׁ, כַּף נַעַר\nרֶגֶל אִשָּׁה, רֹאשׁ הָהָר  \nאַיֵּה הָעֵץ? עַל־רֹאשׁ הָהָר!\nאַיֵּה הָאֵם וְהַבַּת? הֵנָּה עַל־רֹאשׁ הָהָר׃\nאַיֵּה הַבַּיִת? הוּא עַל־רֹאשׁ הָהָר! \nאַיֵּה הָאֲנָשִׁים? הֵם עַל־רֹאשׁ הָהָר׃  \nהָרַגְלַיִם הָאֵלֶּה עַל־רֺאשׁ הָהָר וְהָרַגְלַיִם הָאֵלֶּה בַּדֶּרֶךְ׃\nהַכּוֹס בְּיַד הָאִישׁ׃ הַכּוֹס תַּחַת הָרֶגֶל׃ הַכּוֹס בְּיַד הָאִשָּׁה׃\nרֶגֶל הַבֵּן בְּיַד הָאָב׃ רֹאשׁ הָאִישׁ הַזֶּה עַל־רֹאשׁ הָאִישׁ הַזֶּה׃\nיַד הָאֵם עַל־רֹאשׁ הַבֵּן׃ רֹאשׁ הַבֵּן עַל־רֹאשׁ הָאָב׃   \nיַד הַבַּת בְּיַד הָאָב׃ רֹאשׁ הַבֵּן בְּיַד הָאָב׃ \nהַיָּד הַזֹּאת עַל־הַבֶּטֶן וְהַיָּד הַזֹּאת תַּחַת הַבֶּטֶן׃ \nהַיָּד בַּפֶּה׃ הָרֶגֶל בַּפֶּה׃ יַד הָאָח בְּיַד הָאָחוֹת׃\n\n\nשָׁלוֹם!\n________________',
