				content:
					'שָׁלוֹם, אֲנִי בֵּת!\n\n\nהַפָּרוֹת בַּדֶּרֶךְ, הוּא בֶּן־הָאִישׁ, בֵּן, בַּת, בָּנִים, הֵם בְּנֵי הָאִישׁ\n   \nבָּנִים                         בְּנֵי הָאִישׁ   \n-  ִים             ←        -  ֵי\n\n\nהִיא אֵשֶׁת הָאִישׁ וְהֵם בְּנֵי הָאִישׁ׃ הִיא אֵשֶׁת הָאִישׁ׃ \nהִיא בַּת הָאִישׁ וְהוּא בֶּן־הָאִישׁ׃ הֵם בְּנֵי הָאִישׁ׃ \n\n\nהִיא בַּת הָאִשָּׁה׃ בַּת, בָּנוֹת, הֵנָּה בְּנוֹת הָאִשָּׁה׃ הֵם בְּנֵי הָאִישׁ׃ \nהֵנָּה בְּנוֹת הָאִשָּׁה׃ הֵם בְּנֵי הָאִשָּׁה׃ הִיא אֵשֶׁת הָאִישׁ וְהֵנָּה בְּנוֹת הָאִישׁ׃ הֵנָּה בְּנוֹת הָאִשָּׁה׃ \nעַ֫יִן, עֵינַ֫יִם, אֵלֶּה עֵינֵי אִישׁ׃                                -  ִים             ←        -  ֵי\nעֵינֵי אִשָּׁה, עֵינֵי חֲמוֹר, אָזְנֵי חֲמוֹר, פָּנִים, פְּנֵי הַנַּעֲרָה  \n\n\n-  ִים             ←        -  ֵי\nפָּנִים             ←        פְּנֵי\n\n\nפְּנֵי הַנַּעֲרָה, עֵינֵי הַנַּעֲרָה, פְּנֵי הַנַּעֲרָה, פִּי הַנַּעֲרָה, אַף הַנַּעֲרָה, פִּי הַנַּעֲרָה, עֵינֵי הַנַּעֲרָה, פְּנֵי הַנַּעֲרָה\nיָד, יָדַ֫יִם, יְדֵי אִישׁ, יְדֵי אִשָּׁה    \nיְדֵי נַעַר, יַד הַבֵּן בְּיַד הָאָב\nיְדֵי הַבֵּן בִּידֵי הָאָב\n  \n\nרֶ֫גֶל, רַגְלַ֫יִם, רַגְלֵי אִשָּׁה, רַגְלֵי הָאִשָּׁה עַל־הָעֵץ\nאָזְנֵי סוּס, עֵינֵי סוּס, פְּנֵי סוּס\nאָזְנֵי עֵז, אַף עֵז, פִּי עֵז, פְּנֵי נַעֲרָה  \nמַה־זֶּה? זֶה חֲמוֹר קָטֹן׃ אֵלֶּה רַגְלֵי הַחֲמוֹר הַקָּטֹן וְאֵלֶּה אָזְנֵי הַחֲמוֹר הַקָּטֹן׃\nיְדֵי הָאִישׁ, רַגְלֵי הָאִישׁ, פִּי חֲמוֹר, פִּי אִשָּׁה\nזֶה בֵּית הָאִשָּׁה׃ זֶה בֵּית הָאִישׁ׃ זֶה בֵּית הַנַּעַר׃ \n  \n\nהִיא אֵשֶׁת הָאִישׁ, הִיא בַּת הָאִישׁ וְזֶה בֵּית הָאִישׁ׃ בֵּית הָאִישׁ, בַּת הָאִישׁ\nגַּם־הֵנָּה בֵּית הָאִישׁ׃   \n\n\nמִי הוּא? מַה־שְּׁמוֹ? יִשְׁמָעֵאל שְׁמוֹ׃ \nמַה־זֺּאת? פָּרָה! פָּרַת מִי? פָּרַת יִשְׁמָעֵאל הִיא׃\n\n\n-  ָה             ←        -  ַת\nפָּרָה             ←        פָּרַת\n\n\nפָּרַת יִשְׁמָעֵאל\nאֵלֶּה סוּסֵי יִשְׁמָעֵאל׃ (סוּסִים ← סוּסֵי) סוּסֵי יִשְׁמָעֵאל\nאֵלֶּה חֲמֹרֵי יִשְׁמָעֵאל׃ (חֲמֹרִים ← חֲמֹרֵי) חֲמֹרֵי יִשְׁמָעֵאל\nוְאֵלֶּה גְּמַלֵּי יִשְׁמָעֵאל׃ (גְּמַלִּים ← גְּמַלֵּי) גְּמַלֵּי יִשְׁמָעֵאל\nאֵלֶּה בָּתֵּי יִשְׁמָעֵאל׃ (בָּתִּים ← בָּתֵּי) בָּתֵּי יִשְׁמָעֵאל\nוְאֵלֶּה אָהֳלֵי יִשְׁמָעֵאל׃ (אֹהָלִים ← אָהֳלֵי) אָהֳלֵי יִשְׁמָעֵאל\nאֵלֶּה בְּנֵי יִשְׁמָעֵאל׃ (בָּנִים ← בְּנֵי) בְּנֵי יִשְׁמָעֵאל\nוְאֵלֶּה בְּנוֹת יִשְׁמָעֵאל׃ (בָּנוֹת ← בְּנוֹת) בְּנוֹת יִשְׁמָעֵאל\nבָּנִים, בָּנוֹת, בְּנֵי יִשְׁמָעֵאל, בְּנוֹת יִשְׁמָעֵאל  \nאֵלֶּה נְשֵׁי יִשְׁמָעֵאל׃ (נָשִׁים ← נְשֵׁי) נְשֵׁי יִשְׁמָעֵאל\nהֵם בֵּית יִשְׁמָעֵאל׃\n\n\nהִיא פָּרַת הַנַּעֲרָה׃ פָּרַת הַנַּעֲרָה, יְדֵי הַנַּעֲרָה עַל־פְּנֵי הַפָּרָה׃\n  \n\nמִי הוּא? מַה־שְּׁמוֹ? יוֹסֵף בֶּן־יַעֲקֹב שְׁמוֹ׃ \nהוּא יַעֲקֹב אֲבִי יוֹסֵף וְהֵם בְּנֵי יוֹסֵף׃ \n\n\nשֵׁם הָאִישׁ הַזֶּה יִצְחָק, שְׁמוֹ יִצְחָק׃ \nמִי הִיא? אֵשֶׁת יִצְחָק הִיא׃ מַה־שְּׁמָהּ? רִבְקָה שְׁמָהּ! \n\n\nמִי הֵם? בְּנֵי יִצְחָק הֵם, בְּנֵי יִצְחָק, שְׁמוֹ יַעֲקֹב וּשְׁמוֹ עֵשָׂו׃ \nהוּא יַעֲקֹב וּמִי הוּא? שְׁמוֹ לָבָן, לָבָן אֲחִי רִבְקָה׃\nמִי הֵנָּה? בְּנוֹת לָבָן! שְׁמָהּ לֵאָה וּשְׁמָהּ רָחֵל׃ \nמִי הָאִישׁ הַזֶּה? יַעֲקֹב שְׁמוֹ׃ אַיֵּה יַעֲקֹב? עַל־גָּמָל, מִי הֵם? הֵם בְּנֵי יַעֲקֹב וְהֵנָּה נְשֵׁי יַעֲקֹב׃  \nמִי הֵנָּה? שְׁמָהּ רוּת וּשְׁמָהּ נָעֳמִי׃ רוּת וְנָעֳמִי \nהִיא נָעֳמִי וְהוּא אִישׁ נָעֳמִי׃\nהֵם בְּנֵי נָעֳמִי׃ \nפְּנֵי רוּת, פִּי רוּת, עֵינֵי רוּת\n  \n  \n\nהַדָּבָר הַזֶּה טוֹב בְּעֵינֵי הַנַּעַר׃\nהַדָּבָר הַזֶּה רַע בְּעֵינֵי הָאִשָּׁה׃\nהַדָּבָר הַזֶּה טוֹב בְּעֵינֵי הָאִשָּׁה׃ \nהַדָּבָר הַזֶּה רַע בְּעֵינֵי הָאִישׁ׃ \nהַדָּבָר הַזֶּה טוֹב בְּעֵינֵי הַנַּעֲרָה וְהַדָּבָר הַזֶּה רַע בְּעֵינֵי הַנַּעֲרָה׃  \nהַדָּבָר הַזֶּה רַע בְּעֵינֵי הַנַּעֲרָה׃\nהֲטוֹב הַדָּבָר הַזֶּה בְּעֵינֵי הָאִישׁ? טוֹב הוּא, טוֹב הַדָּבָר! \nהֲטוֹב הַדָּבָר הַזֶּה בְּעֵינֵי הָאִישׁ? לֹא, כִּי רַע הַדָּבָר בְּעֵינֵי הָאִישׁ׃   \nהֲטוֹב הַדָּבָר הַזֶּה בְּעֵינֵי הָאִשָּׁה? \nלֹא, כִּי רַע הַדָּבָר בְּעֵינֵי הָאִשָּׁה׃ \nהֲטוֹב הַדָּבָר הַזֶּה בְּעֵינֵי הָאִשָּׁה? טוֹב הַדָּבָר! \nהֲטוֹב הַדָּבָר הַזֶּה בְּעֵינֵי הָאִישׁ? \nלֹא, כִּי רַע הַדָּבָר בְּעֵינֵי הָאִישׁ׃\nשָׁלוֹם!\n________________',
