					'מַ֫יִם, יָם  \nיַד אִשָּׁה בַּמַּ֫יִם׃ הַנַּ֫עַר בַּמַּ֫יִם׃ רַגְלֵי הָאִישׁ בַּמַּיִם׃\nיָם ← יַמִּים\nיַם־סוּף, יָם הַמֶּ֫לַח, יָם־כִּנֶ֫רֶת, הַיָּם הַגָּדוֹל, יַמִּים                 ָ ה ←  ַ ת\nשָׂפָה, שְׂפַת הָאִשָּׁה, שְׂפַת הַיָּם                                           שָׂפָה ← שְׂפַת \nשְׁנֵי אֲנָשִׁים עַל־שְׁנֵי סוּסִים עַל־שְׂפַת הַיָּם׃  \nמַיִם, פְּנֵי אִישׁ, פְּנֵי הַמַּיִם\nהָאִישׁ עַל־פְּנֵי הַמַּיִם׃\nשָׁמַ֫יִם, יָם וְשָׁמַ֫יִם, הַיָּם וְהַשָּׁמַ֫יִם    \nאֶ֫רֶץ וְשָׁמַיִם, הָאָ֫רֶץ וְהַשָּׁמַיִם\nשֶׁ֫מֶשׁ, הַשֶּׁ֫מֶשׁ בַּשָּׁמַיִם׃\nיָרֵחַ, גַּם־הַיָּרֵחַ בַּשָּׁמַיִם׃  \nעָנָן, גַּם־הֶעָנָן בַּשָּׁמַיִם׃\nהַשֶּׁמֶשׁ בַּשָּׁמַיִם, הַיָּרֵחַ בַּשָּׁמַיִם, עָנָן בַּשָּׁמַיִם\nיוֹם, לַ֫יְלָה  \nהָאִישׁ בַּמִּדְבָּר יוֹמָם׃\nהָאִישׁ בַּמִּדְבָּר לַ֫יְלָה׃\nהָאֹהֶל בַּשָּׂדֶה לַיְלָה׃ ←\nעֵצִים יוֹמָם, עֵצִים לַיְלָה\nהַשָּׁמַיִם יוֹמָם, הַשָּׁמַיִם לַיְלָה    \nמַה־זֶּה? זֶה כֶּ֫לֶב׃\nמַה־זֶּה? זֶה נָחָשׁ׃\n\n\nהַנָּחָשׁ בַּמַּיִם׃\nדָּג אוֹ דָּגָה, דְּגַת הַיָּם                                                 ָ ה ←  ַ ת\nכֶּ֫לֶב, נָחָשׁ, דָּג אוֹ דָּגָה                                                דָּגָה ← דְּגַת\nעוֹף, עוֹף הַשָּׁמַיִם  \nכֶּלֶב, נָחָשׁ, דָּג אוֹ דָּגָה, עוֹף\nפְּנֵי הַמַּיִם, עוֹף עַל־פְּנֵי הַמַּיִם\nדְּגַת הַיָּם, עוֹף הַשָּׁמַיִם\nיֵשׁ\nמַה־זֶּה? זֶה כַּד׃ הֲיֵשׁ מַיִם בַּכַּד? יֵשׁ! יֵשׁ מַיִם בַּכַּד! כַּד מַיִם\nאַ֫יִן\nגַּם־זֶה כַּד׃ הֲיֵשׁ מַיִם בַּכַּד? אַ֫יִן, אֵין מַיִם בַּכַּד׃                 אַ֫יִן ← אֵין  \nאֵין בַּכַּד מַיִם׃ יֵשׁ בַּכַּד מַיִם׃\nכַּד, כַּד, כַּדִּים, שְׁנֵי כַדִּים ←🏺🏺\nיֵשׁ מַיִם בַּכַּד הַזֶּה׃ ✔️💧\nאֵין מַיִם בַּכַּד הַזֶּה׃ אֵין בַּכַּד הַזֶּה מַיִם׃ ❌💧  \nמַה־זֹּאת? זֹאת כּוֹס׃ \nהֲיֵשׁ בַּכּוֹס מַיִם? הִנֵּה מַיִם, יֵשׁ בַּכּוֹס מַיִם׃ זֹאת כּוֹס מַיִם׃\nהֲיֵשׁ בַּכּוֹס מַיִם? אַיִן, אֵין בַּכּוֹס מַיִם׃\nיֵשׁ בַּכּוֹס הַזֹּאת מַיִם׃ אֵין בַּכּוֹס הַזֹּאת מַיִם׃ יֵשׁ, אַיִן  \nיֵשׁ בַּכּוֹס מַיִם׃✔️💧 אֵין בַּכּוֹס מַיִם׃❌💧\nמַה־יֵּשׁ בַּשָּׂדֶה? יֵשׁ בַּשָּׂדֶה אִשָּׁה׃\nהֲיֵשׁ פַּר? אַיִן, אֵין פַּר בַּשָּׂדֶה׃\nמַה־יֵּשׁ לִפְנֵי הַבַּיִת הַזֶּה? יֵשׁ לִפְנֵי הַבַּיִת אִישׁ וְעֵז וּפָרִים׃\nהֲיֵשׁ נַעֲרָה לִפְנֵי הַבַּיִת? אַיִן, אֵין נַעֲרָה לִפְנֵי הַבַּיִת׃\nמַה־יֵּשׁ בַּמִּדְבָּר? יֵשׁ אֲנָשִׁים וּגְמַלִּים בַּמִּדְבָּר׃ יֵשׁ בַּמִּדְבָּר אֲנָשִׁים וּגְמַלִּים׃ הֲיֵשׁ בָּתִּים? אַיִן, אֵין בָּתִּים בַּמִּדְבָּר׃\nמַה־יֵּשׁ תַּחַת הָעֵץ? יֵשׁ שְׁתֵּי נָשִׁים תַּחַת הָעֵץ׃  \nמַה־יֵּשׁ בַּשָּׁמַיִם? יֵשׁ יָרֵחַ בַּשָּׁמַיִם׃\nמַה־יֵּשׁ בַּשָּׁמַיִם? יֵשׁ שֶׁמֶשׁ וְעָנָן בַּשָּׁמַיִם׃\nמַה־יֵּשׁ בַּיָּם? יֵשׁ בַּיָּם מַיִם וּדְגַת הַיָּם׃\nמַה־יֵּשׁ עַל־שְׂפַת הַיָּם? יֵשׁ אֲנָשִׁים עַל־שְׂפַת הַיָּם׃\nהֲיֵשׁ בַּשָּׁמַיִם שֶׁמֶשׁ? יֵשׁ שֶׁמֶשׁ בַּשָּׁמַיִם יוֹמָם׃ אֵין שֶׁמֶשׁ בַּשָּׁמַיִם לַיְלָה׃\nהֲיֵשׁ בַּשָּׁמַיִם יָרֵחַ? יֵשׁ בַּשָּׁמַיִם יָרֵחַ לַיְלָה׃ יֵשׁ בַּשָׁמַיִם יָרֵחַ גַּם־לַיְלָה גַּם־יוֹמָם׃  \nמַיִם בְּיַד אִשָּׁה\nמַה־יֵּשׁ בְּיַד אַבְרָם? יֵשׁ בְּיַד אַבְרָם נָחָשׁ׃ יֵשׁ נָחָשׁ בְּיַד אַבְרָם׃\nהֲיֵשׁ דָּבָר בְּיַד אַבְרָם? יֵשׁ דָּבָר, יֵשׁ בְּיַד אַבְרָם דָּבָר׃\nיֵשׁ דָּבָר בַּיָּד הַזֹּאת׃ אֵין דָּבָר בַּיָּד הַזֹּאת׃                          שָׁלוֹם!\n________________',
