					'ג גּ גָ גִ גוּ גֹ גוֹ גֶ גַּ גַּם  \nגָּמָל, גְּמַלִּים\nדָּג, דָּגָה, דְּגַת, דְּגַת הַיָּם\nרֶגֶל, רַגְלַיִם, רַגְלֵי, רַגְלֵי אַבְרָם\nרַגְלֵי אִישׁ, רַגְלֵי אִשָּׁה  \nגָּדוֹל, גְּדוֹלָה, גְּדֹלִים, גְּדֹלוֹת\nבַּיִת גָּדוֹל, הַיָּם הַגָּדוֹל\nיוֹנָה וְדָג גָּדוֹל\nשׂ שׁ ≠ שׂ, שָׂ שׂוֹ שֶׂ שׂוּ שָׂרָה  \nמִי שָׂרָה? שָׂרָה אֵשֶׁת אַבְרָהָם׃\nשָׂדֶה, יִשְׂרָאֵל, שְׂדֵה יִשְׂרָאֵל\nכּ כ כֵּ כִּ כִּי כָּה כֹּה כַּד, כַּדִּים\nכֶּבֶשׂ, כְּבָשִׂים, כְּבָשִׂים רַבִּים, כְּבָשִׂים גְּדֹלִים, כֶּלֶב\nכ ב ≠ כ, כָ כִי כֵה כוֹ כוּ כֶ כֹ כַ  \nך ךְ ךָ         ך ≠ ן         ך ≠ ד\nדֶּרֶךְ, הַדֶּרֶךְ, הַדֶּרֶךְ בַּשָּׂדֶה\nמֶלֶךְ, מֶלֶךְ יִשְׂרָאֵל, בָּתֵּי הַמֶּלֶךְ\nיֵשׁ מֶלֶךְ בְּיִשְׂרָאֵל׃ אֵין מֶלֶךְ בְּיִשְׂרָאֵל׃  \nפּ פ פִּ פָּ פֶּ פֶּה פִּ, פִּי אִשָּׁה, פַּר, פָּרִים, פָּרָה, פָּרוֹת\nפִּי פָרָה, פָּרוֹת גְּדֹלוֹת\nפָּנִים, פְּנֵי, פְּנֵי אִישׁ, פְּנֵי פַר, פְּנֵי פָרָה, פְּנֵי אַבְרָם  \nפ פַר, פָרָה, שָׂפָה, שְׂפָתַיִם, שְׂפַת, שְׂפַת הַיָּם\nף אַף, אַף פָּרָה, אַף אִשָּׁה, כַּף, כַּפַּיִם, כַּף־רֶגֶל  \n\n\nשָׁלוֹם!\n________________\n  שִׁיעוּר  17  שְׁבַע־עֶשְׂרֵה\nמַה־זֹּאת? זֹאת עֵז׃ רַגְלֵי הָעֵז, רֹאשׁ הָעֵז, פִּי הָעֵז, אַף הָעֵז, אָזְנֵי הָאֵז, עֵינֵי הָעֵז, פְּנֵי הָעֵז, בֶּטֶן הָעֵז  \nמָה־אֵלֶּה? אֵלֶּה קַרְנַ֫יִם׃ קֶ֫רֶן, קֶ֫רֶן, קַרְנַ֫יִם\nאֵלֶּה קַרְנֵי הָעֵז׃ יֵשׁ לָעֵז קַרְנַיִם׃ יֵשׁ לַפָּר קַרְנַיִם׃ \nהֲיֵשׁ־לִי קַרְנַיִם? אֵין־לִי קַרְנַיִם׃\nמַה־יֶּשׁ־לִי? יֶשׁ־לִי עֵינַיִם׃ יֶשׁ־לִי אָזְנַיִם׃ יֶשׁ־לִי אַף׃ יֶשׁ־לִי שְׂפָתַיִם׃ יֶשׁ־לִי פָּנִים׃ אֵין־לִי קַרְנַיִם׃\nיֶשׁ־לָךְ קַרְנַיִם׃ אַיִן! אֵין־לִי קַרְנַיִם׃\nאַבְרָם הֲיֵשׁ לְךָ יָדַיִם? יֶשׁ־לִי יָדַיִם׃                         לְ + אֲנִי ← לִי\nהֲיֵשׁ לְךָ עֵינַיִם? יֶשׁ־לִי עֵינַיִם׃                                לְ + אַתָּה ← לְךָ\nהֲיֵשׁ לְךָ אָזְנַיִם? יֶשׁ־לִי אָזְנַיִם׃                                לְ + אַתְּ ← לָךְ\nהֲיֵשׁ לְךָ שְׂפָתַיִם? יֶשׁ־לִי שְׂפָתַיִם׃  \nהֲיֵשׁ לְךָ קַרְנַיִם? אֵין־לִי קַרְנַיִם! \nהִנֵּה קַרְנַיִם! יֶשׁ־לְךָ קַרְנַיִם!\n\n\nבֵּת 🗨 לִי כַּד גָּדוֹל, לְךָ כַּד קָטֹן׃  \nאַבְרָם 🗨 הִנֵּה נָחָשׁ גָּדוֹל מְאֹד!\nבֵּת 🗨 אַיֵּה? אַיֵּה הַנָּחָשׁ?\nאַבְרָם 🗨 לִי הַכַּד הַגָּדוֹל׃ לָךְ הַכַּד הַקָּטֹן׃\nלְ + הוּא ← לוֹ\nלְ + הִיא ← לָהּ\nמַה־יֵּשׁ לְאַבְרָם? לְאַבְרָם דְּבָרִים רַבִּים׃ יֶשׁ־לוֹ פַּר׃ יֶשׁ־לוֹ סוּס׃ יֶשׁ־לוֹ דָּג׃ יֶשׁ־לוֹ כֶּלֶב׃ יֶשׁ־לוֹ כֶּבֶשׂ׃ יֶשׁ־לוֹ פָּרָה׃ יֶשׁ־לוֹ כַּד׃ יֶשׁ־לוֹ דְּבָרִים רַבִּים׃\nאַבְרָם 🗨 הֲיֵשׁ־לָךְ דְּבָרִים רַבִּים?         בֵּת 🗨 אַיִן!\nאַבְרָם 🗨 הֲיֵשׁ־לָךְ פַּר?                         בֵּת 🗨 אַיִן!\nאַבְרָם 🗨 הֲיֵשׁ־לָךְ דָּג?                         בֵּת 🗨 אַיִן!\nאַבְרָם 🗨 הֲיֵשׁ־לָךְ כַּד?                         בֵּת 🗨 אֵין־לִי כַּד׃ אֵין־לִי דָּבָר׃\nאַבְרָם 🗨 הֲיֵשׁ־לָךְ כֶּבֶשׂ? \nבֵּת 🗨 אֵין־לִי כֶּבֶשׂ׃ אֵין־לִי דָּבָר׃ אֵין־לִי פַּר׃ אֵין־לִי פָּרָה׃ אֵין־לִי כַּד׃ אֵין־לִי מְאוּמָה!\nאַבְרָם 🗨 הִנֵּה לָךְ הַפָּר הַזֶּה! בֵּת 🗨 לִי? יֶשׁ־לִי פַּר!\nהֲיֵשׁ לְאַבְרָם פַּר? אֵין־לוֹ פַּר׃ יֶשׁ־לוֹ פָּרָה׃\nלִי הַפָּר׃ לוֹ הַפָּרָה׃ יֶשׁ־לִי פַּר׃\nאַבְרָם 🗨 אֲנִי אַבְרָם וְאַתְּ אֵשֶׁת אַבְרָם׃                לְ + אֲנַחְנוּ = לָ֫נוּ\nהִנֵּה לָ֫נוּ כָּל־הַדְּבָרִים׃ כָּל־הַדְּבָרִים לָנוּ׃\nמַה־יֶּשׁ־לָנוּ? יֶשׁ־לָנוּ כֶּבֶשׂ׃ יֶשׁ־לָנוּ כֶּלֶב׃ יֶשׁ־לָנוּ דָּג׃ יֶשׁ־לָנוּ צֹאן וּבָקָר׃\nיֶשׁ־לָנוּ כַּד׃ יֶשׁ־לָנוּ פָּרָה׃ יֶשׁ־לָנוּ סוּס׃ יָפֶה! יֶשׁ־לָנוּ דְּבָרִים רַבִּים!\n                                                                             לְ + אַתֶּם = לָכֶם\nמַה־יֵּשׁ לָכֶם? הֲיֵשׁ־לָכֶם בָּקָר? הֲיֵשׁ־לָכֶם צֹאן? הֲיֵשׁ־לָכֶם אֹהָלִים וּבָתִּים? הֲיֵשׁ־לָכֶם בָּתִּים גְּדוֹלִים? מַה־יֵּשׁ לָכֶם?  \n                                                                                     לְ + הֶם = לָהֶם\n                            לְ + הֵנָּה = לָהֶן\n\n\nבֵּת 🗨 יֶשׁ־לִי דָג׃ \nאַבְרָם 🗨 יֶשׁ־לִי חֲמוֹר׃ \nבֵּת 🗨 אַבְרָם, יֶשׁ־לְךָ חֲמוֹר׃ \nאַבְרָם 🗨 יֶשׁ־לָךְ דָּג׃ \nבֵּת 🗨 יֶשׁ־לָנוּ דָּג וַחֲמוֹר׃\nמַה־יֵּשׁ לַנַּעַר? מַה־יֶּשׁ־לוֹ? יֶשׁ־לוֹ גָּמָל׃  \nמַה־יֵּשׁ לָאִשָּׁה? מַה־יֶשׁ־לָהּ? יֶשׁ־לָהּ כֶּבֶשׂ׃\nמַה־יֵּשׁ לָאֲנָשִׁים? מַה־יֵּשׁ לָהֶם׃ יֵשׁ־לָהֶם סוּס אֶחָד׃\nמַה־יֵּשׁ לַנְּעָרוֹת? מַה־יֵּשׁ לָהֶן׃ יֵשׁ־לָהֶן פָּרוֹת׃ יֵשׁ־לָהֶן שְׁתֵּי פָרוֹת׃\nיֶשׁ־לוֹ גָּמָל׃ יֶשׁ־לָהּ כֶּבֶשׂ׃ יֵשׁ־לָהֶם סוּס׃ יֵשׁ־לָהֶן פָּרוֹת׃\n________________\n  \n  \n\n\n\n\n\nבֵּת 🗨                 שָׁלוֹם! \nהָאִשָּׁה הַקְּטַנָּה 🗨  שָׁלוֹם! \nבֵּת 🗨                  מַה־יֶּשׁ־לָךְ? \nהָאִשָּׁה הַקְּטַנָּה 🗨 יֶשׁ־לִי כַּד קָטֹן׃\n\n\n\n\nבֵּת 🗨                 שָׁלוֹם! \nהָאִישׁ הַקָּטֹן 🗨         שָׁלוֹם! \nבֵּת 🗨                  מַה־יֶּשׁ־לְךָ? \nהָאִישׁ הַקָּטֹן 🗨         יֶשׁ־לִי דָּג גָּדוֹל׃\n________________\n\n\nבְּרֵאשִׁית  16׃29 Scroll on WhatsApp 2.19.352 \nוּלְלָבָן שְׁתֵּי בָנוֹת שֵׁם הַגְּדֹלָה לֵאָה וְשֵׁם הַקְּטַנָּה רָחֵל׃\n________________\n\n\nשָׁלוֹם!\n________________',
