					'שָׁלוֹם, אֲנִי בֵּת!\nשְׁלֹמֹה לָקַח אֶת־בַּת־פַּרְעֹה לוֹ לְאִשָּׁה׃ לִשְׁלֹמֹה הָיוּ נָשִׁים רַבּוֹת וִילָדִים רַבִּים׃\nאֵין + הוּא ← אֵינֶ֫נּוּ\nאֵין + אֲנִי ← אֵינֶ֫נִּי\nאֵינֶ֫נּוּ, אֵינֶ֫נִּי\nכִּי אִם־\nאֵינֶ֫נִּי פָּרָה׃ אֵינֶ֫נִּי פָּרָה כִּי אִם־אִשָּׁה׃\nאֵינֶ֫נּוּ חֲמוֹר כִּי אִם־גִּבּוֹר׃\n✔ אֱמֶ֫ת      שֶׁ֫קֶר✘\nאֱמֶ֫ת אוֹ שֶׁ֫קֶר?\n🐍 זֶה פַּר׃ אֱמֶ֫ת אוֹ שֶׁ֫קֶר? שֶׁקֶר!✘ אֵינֶנּוּ פַּר כִּי אִם־נָחָשׁ׃ \n⛺ זֶה אֹהֶל׃ אֱמֶת אוֹ שֶׁקֶר? אֱמֶת! ✔ זֶה אֹהֶל, אֱמֶת!\n🐑 הַכֶּבֶשׂ הַזֶּה גָּדוֹל מְאֹד׃ אֱמֶת אוֹ שֶׁקֶר? שֶׁקֶר!✘ אֵינֶנּוּ גָּדוֹל כִּי אִם־קָטֹן מְאֹד׃\nאַבְרָם נָתַן־לִי כֶּסֶף׃ אֱמֶת אוֹ שֶׁקֶר? שֶׁקֶר!✘ לֹא נָתַן־לִי כֶּסֶף כִּי אִם־זָהָב׃ \nהַיָּם סָבִיב לָעִיר׃ אֱמֶת אוֹ שֶׁקֶר? אֱמֶת! ✔ הַיָּם סָבִיב לָעִיר׃\n[אַתְּ פָּרָה!] אֱמֶת אוֹ שֶׁקֶר? שֶׁקֶר!✘ אֵינֶנִּי פָּרָה כִּי אִם־אִשָּׁה׃ \nאַבְרָם 🗨 אֱמֶת הַדָּבָר!\nבֵּת 🗨 לֹא כִּי שֶׁקֶר הַדָּבָר! אֵינֶנִּי פָּרָה!\n\n\nבֵּת 🗨 אַבְרָם, קוּם! קוּם! [אַבְרָם קָם ↑🧍🏽‍♂️] אַבְרָם קָם׃ אָמַרְתִּי קוּם׃ אַבְרָם קָם׃ שֵׁב! שֵׁב! [אַבְרָם יָשַׁב ↓🧘🏽] אַבְרָם יָשַׁב׃ אָמַרְתִּי שֵׁב׃ אַבְרָם יָשַׁב׃\nקוּם! שֵׁב! קוּם! שֵׁב! קוּם! שֵׁב!\nאָמַרְתִּי קוּם וּמֶה עָשִׂיתָ? \nאַבְרָם 🗨 קַמְתִּי׃ \nבֵּת 🗨 קַמְתָּ׃ וְאַחֲרֵי־כֵן אָמַרְתִּי שֵׁב וּמֶה עָשִׂיתָ? \nאַבְרָם 🗨 יָשַׁבְתִּי׃ \nבֵּת 🗨 יָשַׁבְתָּ׃ קוּם! קוּם! קוּם! [אַבְרָם לֹא קָם]\nאָמַרְתִּי קוּם וְלֹא קָם׃ אַבְרָם לֹא שָׁמַע בְּקוֹלִי׃\nאַבְרָם 🗨 קוּמִי אַתְּ! קוּמִי! [בֵּת קָ֫מָה] בֵּת שָׁמְעָה בְּקוֹלִי׃ שְׁבִי! שְׁבִי! [בֵּת יָשְׁבָה]\n________________\n\n\nבֵּת 🗨 אַבְרָם, קוּם מֵעַל הַכִּסֵּא׃ [אַבְרָם קָם] לֵךְ, שֵׁב עַל־הָאֲדָמָה׃ [אַבְרָם הָלַךְ וַיֵּ֫שֶׁב עַל־הַאֲדָמָה] קוּם מֵעַל הַאֲדָמָה! [אַבְרָם קָם]\nבּוֹא! [אַבְרָם בָּא] שֵׁב! [אַבְרָם יָשַׁב]\n________________\n\n\nבֵּת 🗨 אַבְרָם, קוּם! [אַבְרָם קָם] לֵךְ אֶל־הַנָּהָר׃ שֵׁב עַל־הָאֶבֶן אֲשֶׁר עַל־שְׂפַת הַנָּהָר׃ [אַבְרָם הָלַךְ וַיֵּ֫שֶׁב עַל־הָאֶבֶן] קוּם מֵעַל הָאֶבֶן! [אַבְרָם קָם] בּוֹא! [אַבְרָם בָּא] יָפֶה! שֵׁב עַל־כִּסְאֲךָ׃ [אַבְרָם יָשַׁב] קוּם מֵעַל כִּסְאֲךָ׃ [אַבְרָם קָם] שֵׁב עַל־אִשְׁתְּךָ׃ [אַבְרָם יָשַׁב עַל־בֵּת]\n________________\n\n\nבֵּת 🗨 אַבְרָם, שְׁמַע! שְׁמַע! [קוֹל בָּקָר] שְׁמַע! מַה־שָּׁמַעְתָּ? \nאַבְרָם 🗨  שָׁמַעְתִּי קוֹל בָּקָר׃\nבֵּת 🗨 אַבְרָם, דַּבֵּר! דַּבֵּר! \nאַבְרָם 🗨 בָּבֶל בָּבֶלְבָּבֶלְבָּבֶלְבָּבֶלְבָּבֶלְבָּבֶלְבָּבֶל׃ \nבֵּת 🗨 מֶה עָשִׂיתָ? \nאַבְרָם 🗨 דִּבַּ֫רְתִּי׃ \nבֵּת 🗨 דִּבַּ֫רְתָּ׃ אָמַרְתִּי דַּבֵּר׃ אַבְרָם דִּבֶּר׃ דִּבַּ֫רְתָּ׃ \nאַבְרָם 🗨 דִּבַּ֫רְתִּי׃\n________________\n\n\n[בֵּת 🗨 לִי כַּד גָּדוֹל׃ לְךָ כַּד קָטֺן׃ אַבְרָם 🗨 הִנֵּה נָחָשׁ גָּדוֹל מְאֹד! \nבֵּת 🗨 אַיֵּה? אַיֵּה הַנָּחָשׁ? [אַבְרָם לָקַח אֶת־הַכַּד הַגָּדוֹל] אַיֵּה הַנָּחָשׁ?]  \nבֵּת 🗨 אַבְרָם, מָה רָאִיתָ? \nאַבְרָם 🗨 רָאִיתִי נָחָשׁ גָּדוֹל מְאֹד׃\nבֵּת 🗨 אַךְ אֲנִי לֹא רָאִיתִי אֶת־הַנָּחָשׁ׃ דִּבַּרְתָּ אֱמֶת אוֹ שֶׁקֶר? \nאַבְרָם 🗨 דִּבַּרְתִּי שֶׁקֶר׃\nבֵּת 🗨 דִּבַּרְתָּ שֶׁקֶר! אָמַרְתָּ־לִי הִנֵּה נָחָשׁ גָּדוֹל מְאֹד וְלֹא הָיָה נָחָשׁ׃ אַבְרָם, אֵין דְּבַר־אֱמֶת בְּפִיךָ כִּי אִם־דְּבַר שֶׁקֶר׃ אַבְרָם דִּבֶּר שֶׁקֶר וּדְבַר שֶׁקֶר בְּפִיו׃ אַבְרָם, דַּבֵּר אֱמֶת וְלֹא שֶׁקֶר׃ דַּבֵּר אֱמֶת! הַשֶּׁקֶר רַע בְּעֵינֵי יהוה! דַּבֵּר אֱמֶת!\n\n\n\n\nבֵּת 🗨 אַבְרָם, קְרָא! קְרָא! \nאַבְרָם 🗨 בֵּת! \nבֵּת 🗨 לֹא, לֹא! קְרָא בַּסֵּפֶר הַזֶּה׃ קַח אֶת־הַסֵּפֶר וּקְרָא בְּאָזְנַי׃ \nאַבְרָם 🗨📖 אֲרוֹמִמְךָ אֱלוֹהַי הַמֶּלֶךְ׃ \nבֵּת 🗨 יָפֶה! קָרָ֫אתָ בְּאָזְנַי׃ \nאַבְרָם 🗨 קָרָ֫אתִי בְּאָזְנַיִךְ׃\n\n\nאַבְרָם 🗨 בֵּת, קִרְאִי! [בֵּת לָקְחָה אֶת־הַסֵּפֶר מִיַּד אַבְרָם]  \nבֵּת 🗨📄 ״אַתְּ פָּרָה״ 😠 אֵינֶנִּי פָּרָה! שֶׁקֶר הַדָּבָר הַזֶּה! שֶׁקֶר!\n________________\n Scroll on WhatsApp 2.19.352 \n\nבְּרֵאשִׁית 20:15\nוַיֹּאמֶר אֲבִימֶלֶךְ (אֶל־אַבְרָהָם) הִנֵּה אַרְצִי לְפָנֶיךָ בַּטּוֹב בְּעֵינֶיךָ שֵׁב׃\n________________\n Scroll on WhatsApp 2.19.352 \n\nשְׁמוֹת 20:1-2a\nוַיְדַבֵּר אֱלֹהִים אֵת כָּל־הַדְּבָרִים הָאֵלֶּה לֵאמֹר׃ אָנֹכִי יהוה אֱלֹהֶיךָ \n________________\n Scroll on WhatsApp 2.19.352 \n\nדְּבָרִים 6:4 \nשְׁמַע יִשְׂרָאֵל יהוה אֱלֹהֵינוּ יהוה אֶחָד׃ \nאוֹ                 שְׁמַע יִשְׂרָאֵל אֲדֹנָי אֱלֹהֵינוּ אֲדֹנָי אֶחָד׃\n________________\n Scroll on WhatsApp 2.19.352 \n\nיוֹנָה 1:1-2a\nוַיְהִי דְּבַר־יהוה אֶל־יוֹנָה בֶן־אֲמִתַּי לֵאמֹר׃ קוּם לֵךְ אֶל־נִינְוֵה הָעִיר הַגְּדוֹלָה וּקְרָא עָלֶ֫יהָ \n________________\n\n\n(עָלֶיהָ = עַל־הָעִיר, עַל־נִינְוֵה ← עָלֶיהָ) \n\n\nשָׁלוֹם!\n________________',
