					'וַיְהִי בְנֵי יִשְׂרָאֵל בַּמִּדְבָּר וַיְדַבֵּר יהוה אֶל־מֹשֶׁה לֵּאמֹר׃ שְׁלַח אֲנָשִׁים אֶל־אֶרֶץ כְּנַעַן׃ וַיִּקְרָא מֹשֶׁה לִשְׁנֵי עָשָׂר אִישׁ וַיֹּאמֶר אֲלֵיהֶם לְכוּ וּרְאוּ אֶת־הָאָרֶץ, הֲטוֹבָה הִיא אִם־רָעָה, הֲיֵשׁ־בָּהּ עֵץ אִם־אַיִן׃ רְאוּ גַם־אֶת־הָעָם הֶחָזָק הוּא אִם־רָפֶה, הַמְעַט הוּא אִם־רָב׃ וַיִּשְׁלַח אֹתָם אֶל־אֶרֶץ כְּנַעַן׃  \nוַיֵּלְכוּ הַתָּרִים וַיָּבֹאוּ אֶל־הָאָרֶץ וַיִּרְאוּ אֶת־הָעָם וְאֶת־הֶעָרִים וַיִּקְחוּ מִשָּׁם עֲנָבִים וְרִמֹּנִים וּתְאֵנִים׃ וַיָּשֻׁבוּ מִקֵּץ אַרְבָּעִים יוֹם וַיֵּלְכוּ וַיָּבֹאוּ אֶל־מֹשֶׁה וְאֶל־אַהֲרֹן וְאֶל־כָּל־בְּנֵי יִשְׂרָאֵל וַיֹּאמְרוּ בָּאנוּ אֶל־הָאָרֶץ אֲשֶׁר שָׁלַחְתָּ אֹתָנוּ וְגַם זָבַת חָלָב וּדְבַשׁ הִיא וְזֶה־פִּרְיָהּ׃ אַךְ עַם הָאָרֶץ חָזָק מְאֹד וְהֶעָרִים גְּדֹלוֹת מְאֹד׃ אַנְשֵׁי הָאָרֶץ גְּדוֹלִים וַחֲזָקִים מִמֶּנּוּ׃ וַיִּירָא כָל־הָעָם מְאֹד׃    \nוִיהוֹשֻׁעַ בִּן־נוּן וְכָלֵב אֲשֶׁר מִן־הַתָּרִים אָמְרוּ אֶל־כָּל־בְּנֵי יִשְׂרָאֵל לֵאמֹר טוֹבָה הָאָרֶץ מְאֹד מְאֹד, אֶרֶץ זָבַת חָלָב וּדְבַשׁ׃ יהוה אִתָּנוּ וְחָזָק אֱלֹהֵנוּ מֵאַנְשֵׁי הָאָרֶץ׃ וְלֹא שָׁמַע הָעָם בְּקוֹלָם וְלֹא הָלְכוּ אֶל־הָאָרֶץ כִּי יָרְאוּ מִפְּנֵי אַנְשֵׁי כְּנַעַן׃\n________________\n    שִׁיעוּר 52 חֲמִשִּׁים וּשְׁתַּיִם\nשָׁלוֹם, אֲנִי בֵּת!\nוַיֵּלֶךְ אִישׁ בַּדֶּרֶךְ וַיָּבֹא אֶל־עִיר קְטַנָּה וַיֵּלֶךְ אֶל־בַּיִת וַיֵּשֶׁב עַל־כִּסֵּא אֲשֶׁר לִפְנֵי הַבַּיִת׃ וַיָּקָם מֵעַל הַכִּסֵּא וַיָּשָׁב אֶל־הַדֶּרֶךְ׃\nבֵּת 🗨 מֶה עָשִׂיתָ? \nהָאִישׁ 🗨 הָלַכְתִּי בַּדֶּרֶךְ וָאָבֹ֫א אֶל־עִיר קְטַנָּה וָאֵלֵ֫ךְ אֶל־בַּיִת׃ וָאֵשֵׁ֫ב עַל־כִּסֵּא אֲשֶׁר לִפְנֵי הַבַּיִת׃ וָאָקֻ֫ם מֵעַל הַכִּסֵּא׃ וָאָשֻׁ֫ב אֶל־הַדֶּרֶךְ׃\n\n\nהוּא אָמַר ← וַיֹּ֫אמֶר\nהִיא אָמְרָה ← וַתֹּ֫אמֶר\nאֲנִי אָמַרְתִּי ← וָאֹמַ֫ר\n\n\nאִישׁ בָּא אֵלַי וָאֹמַ֫ר אֵלָיו שָׁלוֹם וַיֹּאמֶר אֵלַי שָׁלוֹם וָאֹמַר אֵלָיו מַה־יֶּשׁ־לְךָ וַיֹּאמֶר אֵלַי יֶשׁ־לִי דָּג גָּדוֹל׃\nוָאָבֹ֫א עַד־שְׂפַת הַנָּהָר וָאֵשֵׁ֫ב שָׁם עַל־אֶבֶן גְּדוֹלָה וָאָקֻ֫ם וָאֵלֵ֫ךְ׃\n\n\n[בֵּת אָכְלָה תְּאֵנָה]  \nבֵּת 🗨 מֶה עָשִׂיתִי? רָאִיתִי תְּאֵנָה וָאֶשְׁלַח אֶת־יָדִי וָאֶקַּח אֹתָהּ וָאֹכַל׃ \n\n\n[אַבְרָם שָׁתָה חָלָב]\nאַבְרָם 🗨 מֶה עָשִׂיתִי? רָאִיתִי כּוֹס חָלָב וָאֶשְׁלַח אֶת־יָדִי וָאֶקַּח אֹתָהּ וָאֵשְׁתְּ׃\nאִישׁ קָטֹן 🗨 מֶה עָשִׂית?ת \nאִשָּׁה קְטַנָּה 🗨 בָּאתִי אֶל־בֵּיתִי וָאֶקַּח מְעַט שֶׁמֶן וָאֵשְׁתְּ׃\nאִישׁ קָטֹן 🗨 הֲשָׁתִית שֶׁמֶן? \nאִשָּׁה קְטַנָּה 🗨 שָׁתִיתִי!\nהוּא נָתַן ← וַיִּתֵּ֫ן\nאֲנִי נָתַתִּי ← וָאֶתֵּ֫ן\nאַבְרָם 🗨 וַתֹּאמֶר אֵלַי בֵּת תֶּן־לִי לֶחֶם וָאֶתֶּן־לָהּ לֶחֶם וַתֹּאמֶר תֶּן־לִי אֶבֶן וָאֶתֶּן־לָהּ אֶבֶן וַתֹּאמֶר תֶּן־לִי זָהָב וָאֹמַר אֵלֶיהָ אֵיִן־לִי זָהָב וַיֵּרַע הָדָּבָר בְּעֵינֶיהָ׃ 🙄\n\n\nוַתְּהִי יַלְדָּה בַדֶּרֶךְ וַתֵּרֶא אֶת־אָבִיהָ בַּשָּׂדֶה וַתָּבֹא אֵלָיו וַתְּדַבֵּר עִמּוֹ וַתָּשָׁב׃\n\n\nבֵּת 🗨 מֶה עָשִׂית?\nיַלְדָּה 🗨 הָיִיתִי בַּדֶּרֶךְ׃ וָאֵ֫רֶא אֶת־אָבִי בַּשָּׂדֶה׃ וָאָבֹא אֵלָיו׃ וָאֲדַבֵּ֫ר עִמּוֹ וָאָשֻׁ֫ב׃\n  \n\nמַה־זֹּאת? זֹאת תּוֹלַ֫עַת׃ רֹאשׁ תּוֹלַעַת, הַתּוֹלַעַת אָכְלָה׃ יֵשׁ מְעַט מַיִם עַל־הַתּוֹלַעַת׃\n\n\n\n\n\n\n\n\nאַבְרָם 🗨 שָׁלוֹם!   \nבֵּת 🗨 שָׁלוֹם, אַבְרָם, מֶה עָשִׂיתָ?תָ\nאַבְרָם 🗨 הָלַכְתִּי אֶל־הַשָּׂדֶה וָאֶשָּׂא אֶבֶן וָאֵרֶא תּוֹלַעַת׃ וָאֶשְׁלַח אֶת־יָדִי וָאֶקַּח אֹתָהּ וָאֹכַל׃\nבֵּת 🗨 בֶּאֱמֶת? הֶאָכַלְתָּ תּוֹלַעַת?ת   \nאַבְרָם 🗨 אָכַלְתִּי!\n\n\nהוּא הָלַךְ ← וַיֵּ֫לֶךְ\nאֲנִי הָלַכְתִּי ← וָאֵלֵ֫ךְ\nאֲנַחְנוּ הָלַכְנוּ ← וַנֵּ֫לֶךְ\nוַנֵּ֫לֶךְ וַנָּ֫שָׁב, וַנֵּלֶךְ וַנָּשָׁב׃\nבֵּת וְאַבְרָם 🗨 מֶה עָשִׂינוּ? בָּאנוּ אֶל־הָאֶבֶן וַנֵּ֫שֶׁב עָלֶיהָ וַנָּ֫קָם וַנֵּלֶךְ׃ \n\n\nבֵּת 🗨 יֵשׁ לָכֶם כֶּסֶף רַב! מֶה עֲשִׂיתֶם?ם  \nשְׁנֵי אֲנָשִׁים קְטַנִּים 🗨 הָלַכְנוּ אֶל־בֵּית אַבְשָׁלוֹם וַחֲרָבוֹת בְּיָדֵינוּ וַנִּקְרָא אֵלָיו אַבְשָׁלוֹם וַיֵּצֵא אֵלֵינוּ׃ וַנֹּ֫אמֶר אֵלָיו תֶּן־לָנוּ כֶּסֶף׃ וַיִּירָא אַבְשָׁלוֹם מִפָּנֵינוּ׃ וַיִּתֵּן לָנוּ אֵת כָּל־כַּסְפּוֹ׃ וַנִּקַּח אֹתוֹ וַנֵּלֶךְ׃\nבֵּת 🗨 לֹא טוֹב הַדָּבָר אֲשֶׁר עֲשִׂיתֶם! לֹא עֲשִׂיתֶם הַיָּשָׁר בְּעֵינֵי יהוה׃\nמֹשֶׁה אָמַר אֶל־בְּנֵי יִשְׂרָאֵל…   \n________________\n  \n\nדְּבָרִים 9:9b Scroll on WhatsApp 2.19.352 \nוָאֵשֵׁב בָּהָר אַרְבָּעִים יוֹם וְאַרְבָּעִים לַיְלָה לֶחֶם לֹא אָכַלְתִּי וּמַיִם לֹא שָׁתִיתִי׃\n________________\n\n\nאַבְרָם דִּבֶּר לְפַרְעֹה שֶׁקֶר לֵאמֹר שָׂרָה אֲחֹתִי…\n________________\n\n\nבְּרֵאשִׁית 12:18a, 19 Scroll on WhatsApp 2.19.352 \nוַיִּקְרָא פַרְעֹה לְאַבְרָם וַיֹּאמֶר מַה־זֹּאת עָשִׂיתָ לִּי… לָמָ֫ה אָמַרְתָּ אֲחֹ֫תִי הִוא וָאֶקַּח אֹתָהּ לִי לְאִשָּׁה וְעַתָּה הִנֵּה אִשְׁתְּךָ קַח וָלֵךְ׃\n________________\n Scroll on WhatsApp 2.19.352 \n\n תְּהִלִּים 22:7a\nוְאָנֹכִי תוֹלַעַת וְלֹא אִישׁ \n________________',
