					'בַּ֫יִת\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם, בַּיִת שֵׁם עֶצֶם׃\n\n\nוַיֵּ֫לֶךְ\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל, וַיֵּלֶךְ פּוֹעַל׃\n\n\nסוּס\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם, סוּס שֵׁם עֶצֶם׃\n  \n\nשֻׁלְחָן\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם, שֻׁלְחָן שֵׁם עֶצֶם׃\n\n\nעָלָה\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל, עָלָה פּוֹעַל׃\nעוֹר\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם, עוֹר שֵׁם עֶצֶם׃\n\n\nחֲנִית\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם  \n\n\nכָּרַת\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n\n\nבָּשָׂר\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n  \n\nרָעָב\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\n\n\nבָּנוּ\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n  \n\nחָלָב\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\nוַיַּעֲבֹר\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n  \n\nעֵ֫בֶר\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n  \n\nרֶ֫כֶב\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\n\n\n\n\nעָלֶה\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n  \n\nפָּרָשׁ\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\nוַתֹּאכַ֫לְנָה\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל  \n\n\nזָנָב\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\nוַתַּ֫הַר  \nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\nזֶ֫רַע\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\nשֵׁן  \nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם  \n\n\nחֹ֫דֶשׁ\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n  \n\nמִסְפָּר\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\nיָלְדָה\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n\n\n\n\nוַיִּתֵּן\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n  \n\nמִנְחָה\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n  \n\nזְרוֹעַ\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n  \n\nשְׁכֶם\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n  \n\nקֶ֫רֶב\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\n\n\nעָמַד  \nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n\n\nוַתִּשְׁתֶּ֫ינָה\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n  \n\nבְּרִית\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם  \n\n\nאֹיֵב\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\nזָכַר / וַיִּזְכֹּר\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n\n\n\n\nוַתֵּבְךְּ\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n\n\nכֹּחַ\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\nוַיִּשְׁתּוּ\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n  \n\nמַקֵּל\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n  \n\nסוּף\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\n\n\nוַתֵּרַ֫דְנָה / וַתֵּשַׁ֫בְנָה\nפְּעָלִים אוֹ שְׁמוֹת עֶצֶם?\nפְּעָלִים\n\n\nרָץ\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n  \n\nדַּ֫עַת\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n  \n\nסַל\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\nגַּן\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\n\n\nצָעַק\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n\n\nצְעָקָה\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n  \n\nמַאֲכָל\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\nנָפְלָה\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n  \n\nמָ֫וֶת\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\n\n\nוַיָּמָת\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n  \n\nחַיִּים\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\nוַיְחִי\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n\n\nוַיַּךְ\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּּוֹעַל\n  \n\nזַיִת\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם׃\n\n\n\n\nיָרְאָה\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nפּוֹעַל\n  \n\nיִרְאָה\nפּוֹעַל אוֹ שֵׁם עֶצֶם?\nשֵׁם עֶצֶם\n\n\n________________',
